#include <bits/stdc++.h>
using namespace std;
int main() {
	long long a, b = 0, x = 0;
	cin >> a >> b;
	for (int i = a; i <= b; i++) {
		if (i % 10 == 2) {
			x++;
		}
		if (i % 100 / 10 == 2) {
			x++;
		}
		if (i % 1000 / 100 == 2) {
			x++;
		}
		if (i / 1000 == 2) {
			x++;
		}
	}
	cout << x;
}
